class Solution:
    def beautySum(self, s):
        from collections import Counter
        n = len(s)
        total = 0
        for i in range(n):
            for j in range(i, n):
                c = Counter(s[i:j + 1])
                vals = c.values()
                total += max(vals) - min(vals)
        return total

