var beautySum = function(s) {
    const n = s.length;
    let total = 0;
    for (let i = 0; i < n; i++) {
        const freq = new Array(26).fill(0);
        for (let j = i; j < n; j++) {
            freq[s.charCodeAt(j) - 97]++;
            let mx = 0, mn = n + 1;
            for (const f of freq) {
                if (f > 0) {
                    if (f > mx) mx = f;
                    if (f < mn) mn = f;
                }
            }
            total += mx - mn;
        }
    }
    return total;
};
